#include <bits/stdc++.h>

using namespace std;

class TrieNode {
 public:
     char c;
     unordered_map<char, TrieNode*> children;
     bool isEndOfWord;

     TrieNode(char c) : c(c), isEndOfWord(false) {}

     bool insert(TrieNode* root, char c) {
         if (root == NULL) return false;

         if (c == ' ') return false;

         if (children.find(c) != children.end())
             return false;

         children[c] = new TrieNode(c);

         return true;
     }

     void preorder() {
         cout << c << ' '; 
         for (auto it : children)
             it.second->preorder();
     }
 }; 

 bool Solution::insert(TrieNode* root, char c) {
     return root->insert(root, c);
 }

 int main() {
     ios_base::sync_with_stdio(false);
     cin.tie(NULL);

     /*
      * Driver code for testing the Solution
      */
     // Create a Trie
     TrieNode* root = new TrieNode('0');

     // Insert strings into the Trie
     for (int i = 0; i < 3; i++)
     {
         cin >> c;
         if (Solution::insert(root, c))
             cout  "String inserted successfully"  endl;
         else
             cout  "String not inserted"  endl;
     }

     // Preorder traversal of the Trie
     root->preorder();

     return 0;
 }

