import sys
from collections import defaultdict
from pprint import pprint

class TrieNode:
     def __init__(self, c):
         self.c = c
         self.isEndOfWord = False
         self.children = defaultdict(TrieNode)

     def insert(self, c):
         if self is None:
             return False

         if c == ' ':
             return False

         if c in self.children:
             return False

         self.children[c] = TrieNode(c)

         return True

class Solution:
     def insert(self, root, c):
         if root is None:
             return False

         if c == ' ':
             return False

         if c in root.children:
             return False

         root.children[c] = TrieNode(c)

         return True

if __name__ == '__main__':
     # Create a Trie
     root = TrieNode('\0')

     # Insert strings into the Trie
     strings = sys.stdin.readline().strip().split()  # Get input strings from standard input
     for c in strings:
         if Solution().insert(root, c):
             print("String inserted successfully")
         else:
             print("String not inserted")

     # Preorder traversal of the Trie
     def preorder(node):
         if node is not None:
             print(node.c, end=' ')  # Print character
             for it in node.children:
                 preorder(node.children[it])  # Recursively preorder traverse children

     preorder(root)
